  9	void usage(void)
 10	{
 11	  printf(
 12	    "usage: <number of tags> <input record file> <output curated record file>\n"
 13	    "options:\n"
 14	    "    -d <database file>        this option is mandatory\n"
 15	    "    -e <event name>           trace given event (default CALIBRATION_CHANNEL_ESTIMATES)\n"
 16	  );
 17	  exit(1);
 18	}
