 22	typedef struct {
 23	  OBUF b;
 24	  struct timespec t;
 25	  int filled;
 26	  int error;
 27	} cache_t;
 28	
 29	void clear_cache(int n, cache_t *c)
 30	{
 31	  int i;
 32	  for (i = 0; i < n; i++) {
 33	    c[i].filled = 0;
 34	    c[i].error = 0;
 35	    c[i].b.osize = 0;
 36	  }
 37	}
 38	
 39	void store_in_cache(cache_t *c, int pos, OBUF *b)
 40	{
 41	  int i;
 42	  for (i = 0; i < b->osize; i++)
 43	    PUTC(&c[pos].b, b->obuf[i]);
 44	}
