 84	int main(int n, char **v)
 85	{
 86	  char *database_filename = NULL;
 87	  void *database;
 88	  int  channel_estimate_id;
 89	  int  number_of_tags = -1;
 90	  char *input_filename = NULL;
 91	  char *output_filename = NULL;
 92	  char *event_name = "CALIBRATION_CHANNEL_ESTIMATES";
 93	  int  i;
 94	  FILE *in;
 95	  FILE *out;
 96	  database_event_format f;
 97	  int  frame_arg;
 98	  int  subframe_arg;
 99	  int  tag_arg;
100	
101	  cache_t *cache;
102	  int     cur_frame = -1;
103	  int     cur_subframe = -1;
104	  int     frame;
105	  int     subframe;
106	  int     tag;
107	
108	  for (i = 1; i < n; i++) {
109	    if (!strcmp(v[i], "-h") || !strcmp(v[i], "--help")) usage();
110	    if (!strcmp(v[i], "-d")) { if (i > n-2) usage();
111	      database_filename = v[++i]; continue; }
112	    if (!strcmp(v[i], "-e")) { if (i > n-2) usage();
113	      event_name = v[++i]; continue; }
114	    if (number_of_tags == -1) { number_of_tags = atoi(v[i]);
115	      if (number_of_tags <= 0) {usage();} continue; }
116	    if (input_filename == NULL) { input_filename = v[i]; continue; }
117	    if (output_filename == NULL) { output_filename = v[i]; continue; }
118	    usage();
119	  }
120	
121	  if (database_filename == NULL) {
122	    printf("ERROR: provide a database file (-d)\n");
123	    exit(1);
124	  }
125	
126	  if (output_filename == NULL || input_filename == NULL || number_of_tags == -1)
127	    usage();
128	
129	  database = parse_database(database_filename);
130	
131	  channel_estimate_id = event_id_from_name(database, event_name);
132	  f = get_format(database, channel_estimate_id);
133	
134	  frame_arg    = get_field(&f, "frame",    "int");
135	  subframe_arg = get_field(&f, "subframe", "int");
136	  tag_arg      = get_field(&f, "tag",      "int");
137	
138	  in = fopen(input_filename, "r");
139	  if (in == NULL) { perror(input_filename); abort(); }
140	  out = fopen(output_filename, "w");
141	  if (out == NULL) { perror(output_filename); abort(); }
142	
143	  cache = calloc(number_of_tags, sizeof(cache_t));
144	  if (cache == NULL) { perror("malloc"); exit(1); }
145	
146	  clear_cache(number_of_tags, cache);
147	
148	  OBUF ebuf = { osize: 0, omaxsize: 0, obuf: NULL };
149	
150	  while (1) {
151	    int type;
152	    int32_t length;
153	    char *v;
154	    int vpos = 0;
155	    struct timespec t = {0};
156	    char *buf;
157	
158	    /* read event from file */
159	    if (fread(&length, 4, 1, in) != 1) break;
160	    if (ebuf.omaxsize < length) {
161	      ebuf.omaxsize = (length + 65535) & ~65535;
162	      ebuf.obuf = realloc(ebuf.obuf, ebuf.omaxsize);
163	      if (ebuf.obuf == NULL) { printf("out of memory\n"); exit(1); }
164	    }
165	    v = ebuf.obuf;
166	    memcpy(v+vpos, &length, 4);
167	    vpos += 4;
168	#ifdef T_SEND_TIME
169	    if (length < sizeof(struct timespec)) { ERR; break; }
170	    if (fread(&t, sizeof(struct timespec), 1, in) != 1) { ERR; break; }
171	    memcpy(v+vpos, &t, sizeof(struct timespec));
172	    vpos += sizeof(struct timespec);
173	    length -= sizeof(struct timespec);
174	#endif
175	    if (length < sizeof(int)) { ERR; break; }
176	    if (fread(&type, sizeof(int), 1, in) != 1) { ERR; break; }
177	    memcpy(v+vpos, &type, sizeof(int));
178	    vpos += sizeof(int);
179	    length -= sizeof(int);
180	    if (length) if (fread(v+vpos, length, 1, in) != 1) { ERR; break; }
181	    buf = v + vpos;
182	    vpos += length;
183	    ebuf.osize = vpos;
184	
185	    if (type != channel_estimate_id) continue;
186	
187	    event e;
188	#ifdef T_SEND_TIME
189	    e = new_event(t, type, length, buf, database);
190	#else
191	    e = new_event(type, length, buf, database);
192	#endif
193	
194	    frame    = e.e[frame_arg].i;
195	    subframe = e.e[subframe_arg].i;
196	    tag      = e.e[tag_arg].i;
197	
198	    if (tag < 0 || tag >= number_of_tags) {
199	      struct tm *tt;
200	      tt = localtime(&t.tv_sec);

    subframe = e.e[subframe_arg].i;
    tag      = e.e[tag_arg].i;

    if (tag < 0 || tag >= number_of_tags) {
      struct tm *tt;
      tt = localtime(&t.tv_sec);
      printf("ERROR: invalid tag (%d), skipping event for frame %d subframe %d (time %2.2d:%2.2d:%2.2d.%9.9ld)\n",
             tag, frame, subframe,
             tt->tm_hour, tt->tm_min, tt->tm_sec, t.tv_nsec);
      continue;
    }

    if (cur_frame != frame || cur_subframe != subframe)
      if (cur_frame != -1)
        process_cache(out, cache, number_of_tags, cur_frame, cur_subframe);

    cur_frame = frame;
    cur_subframe = subframe;

    if (cache[tag].filled) {
      struct tm *tt;
      tt = localtime(&t.tv_sec);
      printf("ERROR: tag %d present twice at frame %d subframe %d (time %2.2d:%2.2d:%2.2d.%9.9ld)\n",
             tag, frame, subframe,
             tt->tm_hour, tt->tm_min, tt->tm_sec, t.tv_nsec);
      cache[tag].error = 1;
      continue;
    }

    store_in_cache(cache, tag, &ebuf);
    cache[tag].filled = 1;
    cache[tag].t = t;
  }

  if (fclose(in)) perror(input_filename);
  if (fclose(out)) perror(output_filename);
  free(cache);

  return 0;
}

